function nextRand(e){return(1103515245*e+12345)%(1<<31)}function genPerm(e,r){for(var t=[...Array(e).keys()],n=0;n<e;++n){var a=(r=nextRand(r))%(e-n)+n,o=t[n];t[n]=t[a],t[a]=o}return t}function base64Encode(e){return window.btoa(e)}function base64Decode(e){return window.atob(e)}function FYForward(e,r){for(var t=base64Encode(e),n=(t=t.replace(/=+$/,"")).length,a=genPerm(n,r),o="",c=0;c<n;++c)o+=t[a[c]];return o}function FYBackward(e,r){for(var t=e.length,n=genPerm(t,r),a=[],o=0;o<t;++o)a[n[o]]=e[o];return base64Decode(a.join(""))}function mailtoClass(e,r){e="."+e;var t=document.querySelectorAll(e);Array.prototype.forEach.call(t,function(e,t){var n=FYBackward(e.dataset.content,r),a=document.createElement("a"),o=[],c=encodeURIComponent;for(var l of["cc","bcc","subject","body"])if(l in e.dataset)if("c"==l[l.length-1])for(var d of e.dataset[l].split(","))o.push(l+"="+c(d));else o.push(l+"="+c(e.dataset[l]));var f="";if(o.length>0)for(var i of(f="?"+o.shift(),o))f+="&"+i;a.href="mailto:"+n+f,a.text=n,e.parentNode.replaceChild(a,e)})}function unscrambleClass(e,r){e="."+e;var t=document.querySelectorAll(e);Array.prototype.forEach.call(t,function(e,t){var n=FYBackward(e.dataset.content,r);e.insertAdjacentHTML("beforebegin",n),e.parentNode.removeChild(e)})}function scrambleClass(e,r){e="."+e;var t=document.querySelectorAll(e);Array.prototype.forEach.call(t,function(e,t){var n=FYForward(e.dataset.content,r);e.insertAdjacentHTML("beforebegin",n),e.parentNode.removeChild(e)})}